    BYTE byEnable; //ﾇｷﾃｸﾊｶ0-1-
    DWORD dwRecogMode;  
    /*ﾊｶﾍ｣
       bit0-ﾊｶ0-ﾊｶ1-ﾊｶ(ﾎｲﾊｶ)  
       bit1-ﾊｶﾐ｡ﾊｶ0-ﾐ｡ﾊｶ1-ﾊｶ 
       bit2-ﾉｫﾊｶ0-ﾃｳﾉｫﾊｶﾚｱﾊｶﾐ｡ﾊｶﾊｱﾖｹﾃ｣1-ﾉｫﾊｶ
       bit3-ﾅｩﾃｳﾊｶ0-ﾅｩﾃｳﾊｶ1-ﾅｩﾃｳﾊｶ 
       bit4-ﾄ｣ﾊｶ0-ﾄ｣ﾊｶ1-ﾄ｣ﾊｶ
       bit5-ﾖ｡ﾎｻ彾｡ｶﾎｻ0-ﾖ｡ﾎｻ1-ﾎｻ
       bit6-ﾖ｡ﾊｶﾊｶ0-ﾖ｡ﾊｶ1-ﾊｶ 
       bit7-ﾏｻ琢ｺ0-琢ｬ1- 
       bit8-ﾄｦﾐｳﾊｶ0-ﾄｦﾐｳﾊｶ1-ﾄｦﾐｳﾊｶ;
       bit9-ﾄ｣ﾊｽ0-鄒ｯ/ﾖ｡1-ﾚ｣
       bit10-ﾎ｢ﾐ｡ﾆ｣0-ﾃ｣1-ﾎ｢ﾐ｡ﾊｶ(6080)
       bit11-ﾈｫ筌ｺ0-ﾃ｣1-ﾃｰﾈｫ
       bit12-嘨ｽｳﾊｶ: 0-ﾃ｣1-嘨ｽｳﾊｶ
       bit13-ﾆｹﾐｱ: 0-ﾃ｣1-ﾐｱPRS
       bit14-ﾊｶ: 0-ﾃ｣1-ﾊｶPRS
       bit15-筌ｺ0-ﾃ｣1-
       bit16-ﾆｱ弣ｵ筌ｺ0-ﾃ｣1-ﾃｻﾆｱ弣ｵ
       bit17-ﾎ｣ﾆｷ筌ｺ0-ﾃ｣1-ﾎ｣ﾆｷ
       bit18-ﾊｹﾝｳﾊｶ0-ﾃ｣1-ﾊｹﾝｳﾊｶ 
       bit19-ﾆｷﾊｶ0-ﾃ｣1-ﾃｳﾆｷﾊｶ
       bit20-扈ｰﾊｶ0-ﾃ｣1-
       bit21-ﾊｶ0-ﾃ｣1-
    */
    BYTE byVehicleLogoRecog;//ﾊｶ 0-ﾃ｣1-  
   /*
       0-1-ﾄ｣2-3-螢ｬ4-5-ﾊ｣6-7-8-9-10-11-ﾔ･
       12-ﾚ｣13-14-譽ｬ15-16-ﾕ｣17-ﾓ｣18-ﾉ｣19-ﾉ｣20-21-爛ｬ22-ﾂｳ
       23-24-ﾂ｣25-26-27-ﾌｨ28-29-ﾘ｣30-ﾛ｣31-ﾂ｣32-ﾆ｣33-罐ｬ
       34-詝ｬ0xff-ﾈｫ
    */
    BYTE byProvince;//ﾊ｡ﾖｵ
    BYTE byRegion;// ﾖｵ 0-1-ﾅｷﾞ｣2-, 3-ﾅｷ&ﾋｹ(EU&CIS),4-ﾐｶ(Middle East)
    BYTE byCountry;//ﾃｶCOUNTRY_INDEX(ﾖｧﾖ｡COUNTRY_ALL = 0xff,//ALL ﾈｫ)
