    WORD  wTaskNo;
    BYTE  byRes1[2];
    NET_VCA_RECT  struPlateRect;//ﾎｻ
    char  sLicense[MAX_LICENSE_LEN/*16*/];//ﾆｺ
    /*
    ﾍｼﾆｬﾊｶ
    bit0-ﾊｶ0-ﾊｶ1-ﾊｶ 
    bit1-ﾊｶ0-ﾊｶ1-ﾊｶ
    bit2-ﾉｫﾊｶ0-ﾊｶ1-ﾊｶ
    bit3-ﾆｷﾊｶ0-ﾊｶ1-ﾊｶ
    bit4-ﾚｵﾊｶ(ﾊｻ)0-ﾊｶ1-ﾊｶ
    bit5-ﾈｫﾊｶ(ﾊｻ)0-ﾊｶ1-ﾊｶ
    bit6-ﾚｵﾊｶ(ﾊｻ)0-ﾊｶ1-ﾊｶ
    bit7-ﾈｫﾊｶ(ﾊｻ)0-ﾊｶ1-ﾊｶ
    bit8-ﾍｼﾆｬﾊｹﾜ｣0-ﾊｶ1-ﾊｶ
    bit9-ﾏｴﾍｼﾆｬﾊｹ(ﾍｨSDK)0-ﾊｶ1-ﾊｶ
    bit10-ﾏｴﾍｼﾆｬﾊｹ(ﾍｨURL)0-ﾊｶ1-ﾊｶ
    bit11-ﾆｱ弣ｵ0-ﾊｶ1-ﾊｶ
    bit12-ﾖｻ0-ﾊｶ1-ﾊｶ
    bit13-ﾒｼ0-ﾊｶ1-ﾊｶ
    bit14-ﾎ｣ﾆｷ: 0-ﾊｶ1-ﾊｶ
    bit15-璆ｰﾕｾﾋｼ: 0-ﾊｶ1-ﾊｶ
    */
    DWORD  dwRecogOperate;
